/* =========================================
   GLOBAL VARIABLES & CONSTANTS
========================================= */
const texts = [
  "Building Fast Websites!",
  "Crafting Modern UIs!",
  "Responsive Web Experiences!",
];

const TYPE_SPEED = 120;
const DELETE_SPEED = 60;
const PAUSE_TIME = 1800;
const AUTO_PLAY_DELAY = 3000;
const SUCCESS_DELAY = 4000;
const PIXEL_THRESHOLD = 2;
const SLIDE_DIVISOR = 1.5;
const OBSERVER_MARGIN = "-50% 0px -50% 0px";
const SCROLL_DEBOUNCE_TIME = 50;

let textIndex = 0;
let charIndex = 0;
let isDeleting = false;
let typingTimeout;

let activeLinkObserver = null;
let formAbortController = null;

/* =========================================
     UTILITY FUNCTIONS
========================================= */
function debounce(func, wait) {
  let timeout;
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

/* =========================================
     HEADER: THEME TOGGLE (Dark/Light)
========================================= */
function updateTheme() {
  document.body.classList.toggle("light-mode");
  localStorage.setItem(
    "lightMode",
    document.body.classList.contains("light-mode"),
  );
}

function initializeTheme() {
  const toggle = document.getElementById("theme");
  if (!toggle) return;

  const lightMode = localStorage.getItem("lightMode") === "true";

  if (lightMode) {
    document.body.classList.add("light-mode");
    toggle.checked = true;
  }

  toggle.addEventListener("change", updateTheme);
}

/* =========================================
     HEADER: MOBILE MENU (Hamburger)
========================================= */
function initializeMobileMenu() {
  const hamburger = document.getElementById("toggle_button");
  const navMenu = document.getElementById("nav-menu");

  if (!hamburger || !navMenu) return;

  const navLinks = document.querySelectorAll("#nav-menu a");

  const closeMenu = () => {
    navMenu.classList.remove("nav-active");
    hamburger.classList.remove("fa-xmark");
    hamburger.classList.add("fa-bars");
  };

  const toggleMenu = () => {
    navMenu.classList.toggle("nav-active");
    hamburger.classList.toggle("fa-bars");
    hamburger.classList.toggle("fa-xmark");
  };

  hamburger.addEventListener("click", toggleMenu);

  hamburger.addEventListener("keydown", (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      toggleMenu();
    }
  });

  navLinks.forEach((link) => {
    link.addEventListener("click", closeMenu);
  });

  document.addEventListener("click", (e) => {
    if (
      !navMenu.contains(e.target) &&
      !hamburger.contains(e.target) &&
      navMenu.classList.contains("nav-active")
    ) {
      closeMenu();
    }
  });

  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && navMenu.classList.contains("nav-active")) {
      closeMenu();
    }
  });
}

/* =========================================
     NAVIGATION: ACTIVE LINK SPY
========================================= */
function initializeActiveLinks() {
  const sections = document.querySelectorAll("section[id]");
  const navLinks = document.querySelectorAll(".nav-link");

  if (!sections.length || !navLinks.length) return;

  activeLinkObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const id = entry.target.id;

          navLinks.forEach((link) => {
            link.classList.remove("active-link");
            if (link.getAttribute("href") === `#${id}`) {
              link.classList.add("active-link");
              link.setAttribute("aria-current", "page");
            } else {
              link.removeAttribute("aria-current");
            }
          });
        }
      });
    },

    { rootMargin: OBSERVER_MARGIN, threshold: 0 },
  );

  sections.forEach((section) => activeLinkObserver.observe(section));
}

function cleanupActiveLinks() {
  if (activeLinkObserver) {
    activeLinkObserver.disconnect();
  }
}

/* =========================================
      HERO SECTION: TYPING EFFECT
========================================= */
function startTyping(delay) {
  clearTimeout(typingTimeout);
  typingTimeout = setTimeout(typeEffect, delay);
}

function typeEffect() {
  const textElement = document.querySelector(".textEffect");

  if (!textElement || !document.body.contains(textElement)) {
    clearTimeout(typingTimeout);
    return;
  }

  const currentText = texts[textIndex];

  if (isDeleting) {
    charIndex--;
  } else {
    charIndex++;
  }

  textElement.textContent = currentText.slice(0, charIndex);

  if (!isDeleting && charIndex === currentText.length) {
    isDeleting = true;
    startTyping(PAUSE_TIME);
    return;
  }

  if (isDeleting && charIndex === 0) {
    isDeleting = false;
    textIndex = (textIndex + 1) % texts.length;
  }

  startTyping(isDeleting ? DELETE_SPEED : TYPE_SPEED);
}

/* =========================================
     PROJECTS SECTION: CUSTOM SLIDER
========================================= */
function initializeProjectSlider() {
  const slider = document.getElementById("projectSlider");
  const slideLeft = document.getElementById("slideLeft");
  const slideRight = document.getElementById("slideRight");
  const dots = document.querySelectorAll(".slider-dot");

  if (slider && slideLeft && slideRight) {
    let autoPlay;

    const moveRight = () => {
      let isAtEnd =
        Math.abs(slider.scrollWidth - slider.scrollLeft - slider.clientWidth) <=
        PIXEL_THRESHOLD;

      if (isAtEnd) {
        slider.scrollTo({ left: 0, behavior: "smooth" });
        return;
      }
      slider.scrollBy({
        left: slider.clientWidth / SLIDE_DIVISOR,
        behavior: "smooth",
      });
    };

    const moveLeft = () => {
      let isAtStart = slider.scrollLeft <= PIXEL_THRESHOLD;

      if (isAtStart) {
        slider.scrollTo({ left: slider.scrollWidth, behavior: "smooth" });
        return;
      }
      slider.scrollBy({
        left: -(slider.clientWidth / SLIDE_DIVISOR),
        behavior: "smooth",
      });
    };

    slideRight.addEventListener("click", moveRight);
    slideLeft.addEventListener("click", moveLeft);

    const handleScroll = debounce(() => {
      const cardWidth = slider.firstElementChild
        ? slider.firstElementChild.offsetWidth
        : slider.clientWidth;
      let scrollIndex = Math.round(slider.scrollLeft / cardWidth);

      dots.forEach((dot, index) => {
        dot.classList.toggle("active", index === scrollIndex);
      });
    }, SCROLL_DEBOUNCE_TIME);

    slider.addEventListener("scroll", handleScroll, { passive: true });

    dots.forEach((dot, index) => {
      dot.addEventListener("click", () => {
        const cardWidth = slider.firstElementChild
          ? slider.firstElementChild.offsetWidth
          : slider.clientWidth;
        slider.scrollTo({ left: cardWidth * index, behavior: "smooth" });
      });
    });

    const startAutoPlay = () => {
      clearInterval(autoPlay);
      autoPlay = setInterval(moveRight, AUTO_PLAY_DELAY);
    };

    const stopAutoPlay = () => {
      clearInterval(autoPlay);
    };

    slider.addEventListener("mouseenter", stopAutoPlay);
    slider.addEventListener("mouseleave", startAutoPlay);

    startAutoPlay();
  }
}

/* =========================================
     CONTACT SECTION: FORM SUBMISSION
========================================= */
function initializeContactForm() {
  const form = document.getElementById("contactForm");
  if (!form) return;

  form.addEventListener("submit", async (e) => {
    e.preventDefault();
    const button = form.querySelector(".form-submit-btn");
    const successMsg = document.getElementById("successMsg");

    if (button.disabled) return;

    button.disabled = true;
    button.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Sending...';

    if (formAbortController) {
      formAbortController.abort();
    }
    formAbortController = new AbortController();

    try {
      const response = await fetch(form.action, {
        method: "POST",
        body: new FormData(form),
        headers: { Accept: "application/json" },
        signal: formAbortController.signal,
      });

      if (!response.ok) throw new Error("Form submission failed");

      form.reset();
      button.innerHTML = '<i class="fa-solid fa-check"></i> Sent Successfully';

      if (successMsg) {
        successMsg.textContent = "Message sent successfully!";
        successMsg.classList.remove("error");
        successMsg.style.display = "block";
        successMsg.style.color = "var(--main-color)";
      }
    } catch (error) {
      if (error.name === "AbortError") {
        console.log("Fetch aborted");
        return;
      }

      button.innerHTML =
        '<i class="fa-solid fa-triangle-exclamation"></i> Try Again';

      if (successMsg) {
        successMsg.textContent = "Something went wrong. Please try again.";
        successMsg.classList.add("error");
        successMsg.style.display = "block";
        successMsg.style.color = "#ff3333";
      }
    } finally {
      setTimeout(() => {
        button.disabled = false;
        button.innerHTML =
          '<i class="fa-regular fa-paper-plane"></i> Send Message';
        if (successMsg) successMsg.style.display = "none";
      }, SUCCESS_DELAY);
    }
  });
}

/* =========================================
     LOADER FALLBACK
========================================= */
function hideLoader() {
  const loader = document.getElementById("loader");
  if (loader && !loader.classList.contains("hide")) {
    loader.classList.add("hide");
  }
}

/* =========================================
     EVENTS: DOMContentLoaded, Load & Unload
========================================= */
document.addEventListener("DOMContentLoaded", () => {
  if (typeof AOS !== "undefined") {
    AOS.init({
      once: false,
      duration: 500,
    });
  }

  initializeTheme();
  initializeMobileMenu();
  initializeActiveLinks();
  initializeProjectSlider();
  initializeContactForm();

  startTyping(TYPE_SPEED);
});

window.addEventListener("load", () => {
  setTimeout(() => {
    hideLoader();

    setTimeout(() => {
      document.body.style.transition = "background-color .5s, color .5s";
    }, 800);
    i;
  }, 500);

  if (typeof AOS !== "undefined") {
    setTimeout(() => {
      AOS.refresh();
    }, 600);
  }
});
window.addEventListener("beforeunload", () => {
  clearTimeout(typingTimeout);
  cleanupActiveLinks();
  if (formAbortController) {
    formAbortController.abort();
  }
});
